function timeToBuyTickets(tickets, k) {
    let time = 0;
    while (tickets[k] > 0) {
        for (let i = 0; i < tickets.length; ++i) {
            if (tickets[i] > 0) {
                --tickets[i];
                ++time;
                if (i === k && tickets[k] === 0) {
                    break;
                }
            }
        }
    }
    return time;
}
